SET NAMES utf8mb4;

-- Stap 1: alle vorige import-data verwijderen
DELETE FROM `m7zN4_ps_koppelingen` WHERE beschikbaarheid_id IN
  (SELECT id FROM `m7zN4_ps_beschikbaarheid` WHERE email LIKE '%@import.prostudents.nl');
DELETE FROM `m7zN4_ps_beschikbaarheid` WHERE email LIKE '%@import.prostudents.nl';
DELETE FROM `m7zN4_ps_diensten` WHERE omschrijving = 'excel-import';

-- Stap 2: 3142 diensten invoegen
















SELECT CONCAT('Klaar: ', COUNT(*), ' diensten geïmporteerd') AS status
FROM `m7zN4_ps_diensten` WHERE status = 'vervuld';